module testcase (
   input correct_clk,
   input reset_q,
   input do0_d,
   output do0,
   );

   reg do0_q;

   assign do0 = do0_q;

   begin : read_data_latched_true
      always @(posedge correct_clk)
      begin: read_data_latches
         if (correct_clk == 1'b1)
         begin
            if (reset_q == 1'b1)
            begin
               do0_q <= 1'b0;
            end
            else
            begin
               do0_q <= do0_d;
            end
         end
      end
   end
endmodule

